/**
 * Setup banner dismiss handler.
 *
 * Calls block_mastermind_assistant_complete_setup, then removes the banner DOM.
 *
 * @module     block_mastermind_assistant/setup_banner
 * @copyright  2026 The Namers <info@mastermindassistant.ai>
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define("block_mastermind_assistant/setup_banner",["core/ajax","core/notification"],(function(Ajax,Notification){return{init:function(){var btn=document.getElementById("mastermind-setup-dismiss");btn&&btn.addEventListener("click",(function(){btn.disabled=!0,Ajax.call([{methodname:"block_mastermind_assistant_complete_setup",args:{}}])[0].then((function(){var banner=document.getElementById("mastermind-setup-banner");return banner&&banner.parentNode&&banner.parentNode.removeChild(banner),null})).catch((function(err){btn.disabled=!1,Notification.exception(err)}))}))}}}));
